={
  "content": "<@YOUR_DISCORD_USER_ID>",
  "embeds": [
    {
      "title": "🔥 FIRING — {{ ($json.body.alerts || [{}])[0].labels?.alertname || 'Grafana Alert' }}",
      "description": "{{ ($json.body.alerts || [{}])[0].annotations?.summary || 'Alert triggered' }}",
      "color": 15158332,
      "fields": [
        {
          "name": "Severity",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.severity || 'unknown' }}",
          "inline": true
        },
        {
          "name": "Source",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.source || 'unknown' }}",
          "inline": true
        },
        {
          "name": "Alert Group",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.alert_group || 'N/A' }}",
          "inline": true
        },
        {
          "name": "Grafana Folder",
          "value": "{{ ($json.body.alerts || [{}])[0].labels?.grafana_folder || 'N/A' }}",
          "inline": true
        },
        {
          "name": "Starts At",
          "value": "{{ ($json.body.alerts || [{}])[0].startsAt || 'N/A' }}",
          "inline": false
        },
        {
          "name": "Details",
          "value": "{{ (($json.body.alerts || [{}])[0].annotations?.description || 'N/A').slice(0, 950) }}",
          "inline": false
        },
        {
          "name": "Dashboard / Panel",
          "value": "{{ ($json.body.alerts || [{}])[0].dashboardURL || 'N/A' }}\n{{ ($json.body.alerts || [{}])[0].panelURL || '' }}",
          "inline": false
        },
        {
          "name": "Labels (raw)",
          "value": "```json\n{{ JSON.stringify((($json.body.alerts || [{}])[0].labels || {}), null, 2).slice(0, 900) }}\n```",
          "inline": false
        }
      ],
      "timestamp": "{{ ($json.body.alerts || [{}])[0].startsAt || new Date().toISOString() }}"
    }
  ]
}

